import{j as l,b as o,c as s,q as t,f as e,a9 as a}from"./chunks/framework.CFGK5tmi.js";const r="/assets/IP%E5%9C%B0%E5%9D%80%E5%88%86%E7%B1%BB.C42g1i8l.jpg",d="/assets/%E7%BD%91%E7%BB%9C%E5%9C%B0%E5%9D%80%E5%92%8C%E5%B9%BF%E6%92%AD%E5%9C%B0%E5%9D%80.9-Icij49.jpg",n="/assets/%E5%AD%90%E7%BD%91%E5%88%92%E5%88%86.CxcQ85aJ.jpg",v=JSON.parse('{"title":"IP","description":"","frontmatter":{},"headers":[],"relativePath":"csbase/network/ip基础.md","filePath":"csbase/network/ip基础.md","lastUpdated":null}'),i={name:"csbase/network/ip基础.md"},T=a('<h1 id="ip" tabindex="-1">IP <a class="header-anchor" href="#ip" aria-label="Permalink to &quot;IP&quot;">​</a></h1><h2 id="概览" tabindex="-1">概览 <a class="header-anchor" href="#概览" aria-label="Permalink to &quot;概览&quot;">​</a></h2><p>IP在TCP/IP模型中位于第三层，网络层。网络层的主要作用：<strong>实现主机与主机之间的通信</strong>（点对点的通信）。IP的作用是在复杂的网络环境中，将数据包发送给最终目的地主机。</p><div class="tip custom-block github-alert"><p class="custom-block-title">TIP</p><p></p><p>网络层与数据链路层之间的关系是什么？二者有何不同</p></div><p>IP 的作用是主机之间通信用的，而 <strong>MAC 的作用则是实现「直连」的两个设备之间通信，而 IP 则负责在「没有直连」的两个网络之间进行通信传输</strong>。在网络中传输数据包，源IP地址和目标IP地址是不变的(除NAT)，只有源MAC地址和目的MAC地址在变化。</p><h2 id="ip的基础知识" tabindex="-1">IP的基础知识 <a class="header-anchor" href="#ip的基础知识" aria-label="Permalink to &quot;IP的基础知识&quot;">​</a></h2><p>在TCP/IP网络通信时，每个设备都需要配置一个正确的IP地址实现网络通信。IP地址（IPV4）由 32 位二进制数字表示，8个为一组，一共分为4组，每组之间用<code>.</code>隔开。</p>',7),p={class:"MathJax",jax:"SVG",style:{direction:"ltr",position:"relative"}},c={style:{overflow:"visible","min-height":"1px","min-width":"1px","vertical-align":"0"},xmlns:"http://www.w3.org/2000/svg",width:"2.919ex",height:"1.887ex",role:"img",focusable:"false",viewBox:"0 -833.9 1290.1 833.9","aria-hidden":"true"},h=a('<g stroke="currentColor" fill="currentColor" stroke-width="0" transform="scale(1,-1)"><g data-mml-node="math"><g data-mml-node="msup"><g data-mml-node="mn"><path data-c="32" d="M109 429Q82 429 66 447T50 491Q50 562 103 614T235 666Q326 666 387 610T449 465Q449 422 429 383T381 315T301 241Q265 210 201 149L142 93L218 92Q375 92 385 97Q392 99 409 186V189H449V186Q448 183 436 95T421 3V0H50V19V31Q50 38 56 46T86 81Q115 113 136 137Q145 147 170 174T204 211T233 244T261 278T284 308T305 340T320 369T333 401T340 431T343 464Q343 527 309 573T212 619Q179 619 154 602T119 569T109 550Q109 549 114 549Q132 549 151 535T170 489Q170 464 154 447T109 429Z" style="stroke-width:3;"></path></g><g data-mml-node="TeXAtom" transform="translate(533,363) scale(0.707)" data-mjx-texclass="ORD"><g data-mml-node="mn"><path data-c="33" d="M127 463Q100 463 85 480T69 524Q69 579 117 622T233 665Q268 665 277 664Q351 652 390 611T430 522Q430 470 396 421T302 350L299 348Q299 347 308 345T337 336T375 315Q457 262 457 175Q457 96 395 37T238 -22Q158 -22 100 21T42 130Q42 158 60 175T105 193Q133 193 151 175T169 130Q169 119 166 110T159 94T148 82T136 74T126 70T118 67L114 66Q165 21 238 21Q293 21 321 74Q338 107 338 175V195Q338 290 274 322Q259 328 213 329L171 330L168 332Q166 335 166 348Q166 366 174 366Q202 366 232 371Q266 376 294 413T322 525V533Q322 590 287 612Q265 626 240 626Q208 626 181 615T143 592T132 580H135Q138 579 143 578T153 573T165 566T175 555T183 540T186 520Q186 498 172 481T127 463Z" style="stroke-width:3;"></path><path data-c="32" d="M109 429Q82 429 66 447T50 491Q50 562 103 614T235 666Q326 666 387 610T449 465Q449 422 429 383T381 315T301 241Q265 210 201 149L142 93L218 92Q375 92 385 97Q392 99 409 186V189H449V186Q448 183 436 95T421 3V0H50V19V31Q50 38 56 46T86 81Q115 113 136 137Q145 147 170 174T204 211T233 244T261 278T284 308T305 340T320 369T333 401T340 431T343 464Q343 527 309 573T212 619Q179 619 154 602T119 569T109 550Q109 549 114 549Q132 549 151 535T170 489Q170 464 154 447T109 429Z" transform="translate(500,0)" style="stroke-width:3;"></path></g></g></g></g></g>',1),Q=[h],m=t("mjx-assistive-mml",{unselectable:"on",display:"inline",style:{top:"0px",left:"0px",clip:"rect(1px, 1px, 1px, 1px)","-webkit-touch-callout":"none","-webkit-user-select":"none","-khtml-user-select":"none","-moz-user-select":"none","-ms-user-select":"none","user-select":"none",position:"absolute",padding:"1px 0px 0px 0px",border:"0px",display:"block",width:"auto",overflow:"hidden"}},[t("math",{xmlns:"http://www.w3.org/1998/Math/MathML"},[t("msup",null,[t("mn",null,"2"),t("mrow",{"data-mjx-texclass":"ORD"},[t("mn",null,"32")])])])],-1),g=t("strong",null,"网卡",-1),_=a('<p>而且因为 IP 地址是由「<strong>网络标识</strong>」和「<strong>主机标识</strong>」这两个部分组成的，所以实际能够连接到网络的计算机个数更是少了很多。但是为了让各自设备（包括手机、电脑、智能手表等）都能有IP地址，有了一种可以更换IP的<code>NAT</code>技术。</p><h3 id="ip地址的分类" tabindex="-1">IP地址的分类 <a class="header-anchor" href="#ip地址的分类" aria-label="Permalink to &quot;IP地址的分类&quot;">​</a></h3><p>在互联网诞生之初，IP地址非常充裕，因此设计出了不同的<strong>分类地址</strong>，分别是 A 类、B 类、C 类、D 类、E 类。前面的几位是分类号，用于区分不同的IP地址类。</p><p><img src="'+r+'" alt="IP 地址分类"></p><p>其中对于 A、B、C 类主要分为两个部分，分别是<strong>网络号和主机号</strong>。它们的ip地址范围如下</p><table tabindex="0"><thead><tr><th>类别</th><th>IP 地址范围</th><th>最大主机数</th></tr></thead><tbody><tr><td>A</td><td>0.0.0.0 ~ 127.255.255.255</td><td>16777214</td></tr><tr><td>B</td><td>128.0.0.0 ~ 191.255.255.255</td><td>65534</td></tr><tr><td>C</td><td>192.0.0.0 ~ 223.255.255.255</td><td>254</td></tr></tbody></table>',6),u={class:"MathJax",jax:"SVG",style:{direction:"ltr",position:"relative"}},x={style:{overflow:"visible","min-height":"1px","min-width":"1px","vertical-align":"-0.186ex"},xmlns:"http://www.w3.org/2000/svg",width:"6.816ex",height:"2.09ex",role:"img",focusable:"false",viewBox:"0 -841.7 3012.6 923.7","aria-hidden":"true"},P=a('<g stroke="currentColor" fill="currentColor" stroke-width="0" transform="scale(1,-1)"><g data-mml-node="math"><g data-mml-node="msup"><g data-mml-node="mn"><path data-c="32" d="M109 429Q82 429 66 447T50 491Q50 562 103 614T235 666Q326 666 387 610T449 465Q449 422 429 383T381 315T301 241Q265 210 201 149L142 93L218 92Q375 92 385 97Q392 99 409 186V189H449V186Q448 183 436 95T421 3V0H50V19V31Q50 38 56 46T86 81Q115 113 136 137Q145 147 170 174T204 211T233 244T261 278T284 308T305 340T320 369T333 401T340 431T343 464Q343 527 309 573T212 619Q179 619 154 602T119 569T109 550Q109 549 114 549Q132 549 151 535T170 489Q170 464 154 447T109 429Z" style="stroke-width:3;"></path></g><g data-mml-node="TeXAtom" transform="translate(533,363) scale(0.707)" data-mjx-texclass="ORD"><g data-mml-node="mn"><path data-c="32" d="M109 429Q82 429 66 447T50 491Q50 562 103 614T235 666Q326 666 387 610T449 465Q449 422 429 383T381 315T301 241Q265 210 201 149L142 93L218 92Q375 92 385 97Q392 99 409 186V189H449V186Q448 183 436 95T421 3V0H50V19V31Q50 38 56 46T86 81Q115 113 136 137Q145 147 170 174T204 211T233 244T261 278T284 308T305 340T320 369T333 401T340 431T343 464Q343 527 309 573T212 619Q179 619 154 602T119 569T109 550Q109 549 114 549Q132 549 151 535T170 489Q170 464 154 447T109 429Z" style="stroke-width:3;"></path><path data-c="34" d="M462 0Q444 3 333 3Q217 3 199 0H190V46H221Q241 46 248 46T265 48T279 53T286 61Q287 63 287 115V165H28V211L179 442Q332 674 334 675Q336 677 355 677H373L379 671V211H471V165H379V114Q379 73 379 66T385 54Q393 47 442 46H471V0H462ZM293 211V545L74 212L183 211H293Z" transform="translate(500,0)" style="stroke-width:3;"></path></g></g></g><g data-mml-node="mo" transform="translate(1512.3,0)"><path data-c="2212" d="M84 237T84 250T98 270H679Q694 262 694 250T679 230H98Q84 237 84 250Z" style="stroke-width:3;"></path></g><g data-mml-node="mn" transform="translate(2512.6,0)"><path data-c="32" d="M109 429Q82 429 66 447T50 491Q50 562 103 614T235 666Q326 666 387 610T449 465Q449 422 429 383T381 315T301 241Q265 210 201 149L142 93L218 92Q375 92 385 97Q392 99 409 186V189H449V186Q448 183 436 95T421 3V0H50V19V31Q50 38 56 46T86 81Q115 113 136 137Q145 147 170 174T204 211T233 244T261 278T284 308T305 340T320 369T333 401T340 431T343 464Q343 527 309 573T212 619Q179 619 154 602T119 569T109 550Q109 549 114 549Q132 549 151 535T170 489Q170 464 154 447T109 429Z" style="stroke-width:3;"></path></g></g></g>',1),I=[P],b=t("mjx-assistive-mml",{unselectable:"on",display:"inline",style:{top:"0px",left:"0px",clip:"rect(1px, 1px, 1px, 1px)","-webkit-touch-callout":"none","-webkit-user-select":"none","-khtml-user-select":"none","-moz-user-select":"none","-ms-user-select":"none","user-select":"none",position:"absolute",padding:"1px 0px 0px 0px",border:"0px",display:"block",width:"auto",overflow:"hidden"}},[t("math",{xmlns:"http://www.w3.org/1998/Math/MathML"},[t("msup",null,[t("mn",null,"2"),t("mrow",{"data-mjx-texclass":"ORD"},[t("mn",null,"24")])]),t("mo",null,"−"),t("mn",null,"2")])],-1),V=a('<p><img src="'+d+'" alt="img"></p><ul><li>在 A 类地址中，如果你有一个 IP 地址范围从 10.0.0.0 到 10.255.255.255，那么 10.0.0.0 就是网络地址。</li><li>对于 B 类地址，如果地址范围是 172.16.0.0 到 172.16.255.255，那么 172.16.0.0 是网络地址。</li><li>对于 C 类地址，例如地址范围是 192.168.1.0 到 192.168.1.255，那么 192.168.1.0 是网络地址。</li></ul><p>广播地址可以分为<em>本地广播</em>和<em>直接广播</em>两种。</p><ul><li><strong>在本网络内广播的叫做本地广播</strong>。例如网络地址为 192.168.0.0/24 的情况下，广播地址是 192.168.0.255 。因为这个广播地址的 IP 包会被路由器屏蔽，所以不会到达 192.168.0.0/24 以外的其他链路上。</li><li><strong>在不同网络之间的广播叫做直接广播</strong>。例如网络地址为 192.168.0.0/24 的主机向 192.168.1.255/24 的目标地址发送 IP 包。收到这个包的路由器，将数据转发给 192.168.1.0/24，从而使得所有 192.168.1.1~192.168.1.254 的主机都能收到这个包（由于直接广播有一定的安全问题，多数情况下会在路由器上设置为不转发。） 。</li></ul><p>D、E 类地址没有主机号，所以不可用于主机 IP，D 类常被用于<strong>多播</strong>，E 类是预留的分类，暂时未使用。</p><table tabindex="0"><thead><tr><th>类别</th><th>IP 地址范围</th><th>用途</th></tr></thead><tbody><tr><td>D</td><td>224.0.0.0 ~ 239.255.255.255</td><td>IP 组播</td></tr><tr><td>E</td><td>240.0.0.0 ~ 255.255.255.255</td><td>保留使用</td></tr></tbody></table><p>多播用于<strong>将包发送给特定组内的所有主机</strong>。当数据发送到一个多播地址时，网络设备（如路由器）会智能地将数据包分发给订阅了该多播组的所有接收者。这意味着数据包不需要对每个接收者单独发送，而是通过网络中的分发点复制和发送，从而节省带宽并减少网络拥堵。</p><h3 id="ip分类的缺点" tabindex="-1">IP分类的缺点 <a class="header-anchor" href="#ip分类的缺点" aria-label="Permalink to &quot;IP分类的缺点&quot;">​</a></h3><p><strong>地址分配不合理</strong>：</p><ul><li>在 A、B 类网络中，很多分配的地址常常未被充分使用。例如，一个 A 类网络可以支持近 一千六百多万 个主机，而大多数组织根本不需要如此庞大的地址空间。这导致大量的 IP 地址被闲置，造成了资源的极大浪费。</li><li>而 C 类网络只有 254 个地址，可能又太少了。</li></ul><p><strong>缺乏灵活性</strong>：</p><ul><li><strong>同一网络下没有地址层次</strong>，比如一个大学里分配了一个B类地址，该校园有多个部门和设施，包括行政楼、教学楼、学生宿舍、图书馆和科研中心。而这种 IP 分类是没有地址层次划分的功能，所以这就<strong>缺少地址的灵活性</strong>。</li></ul><h3 id="cidr" tabindex="-1">CIDR <a class="header-anchor" href="#cidr" aria-label="Permalink to &quot;CIDR&quot;">​</a></h3><p>因为IP地址分类存在缺点，所以引出了<code>CIDR</code>的概念，这种方式不再有分类地址的概念，32 比特的 IP 地址被划分为两部分，前面是<strong>网络号</strong>，后面是<strong>主机号</strong>。</p><p>它的表示形式 <code>a.b.c.d/x</code>，其中 <code>/x</code> 表示前 x 位属于<strong>网络号</strong>， x 的范围是 <code>0 ~ 32</code>，这就使得 IP 地址更加具有灵活性。</p><p>比如 10.100.122.2/24这个ip地址</p><table tabindex="0"><thead><tr><th>项目</th><th>信息</th></tr></thead><tbody><tr><td>可用地址个数</td><td>254</td></tr><tr><td>子网掩码</td><td>255.255.255.0</td></tr><tr><td>网络号</td><td>10.100.122.0</td></tr><tr><td>第一个可用地址</td><td>10.100.122.1</td></tr><tr><td>最后一个可用地址</td><td>10.100.122.254</td></tr><tr><td>广播地址</td><td>10.100.122.255</td></tr></tbody></table><p><strong>将子网掩码和 IP 地址按位计算 AND，就可得到网络号。</strong></p><div class="tip custom-block"><p class="custom-block-title">为什么需要分离网络号和主机号？</p><ol><li>易于划分，而且可以提升安全性</li><li>方便转发，路由器寻址过程组会看网络号</li></ol></div><blockquote><p>怎么划分子网？</p></blockquote><p>利用子网掩码，<strong>子网划分实际上是将主机地址分为两个部分：子网网络地址和子网主机地址</strong>。形式如下：</p><p><img src="'+n+'" alt="img"></p><ul><li>未做子网划分的 ip 地址：网络地址＋主机地址</li><li>做子网划分后的 ip 地址：网络地址＋（子网网络地址＋子网主机地址）</li></ul><hr><p>示例：</p><ul><li><strong>IP 地址</strong>：192.168.1.0/24</li><li><strong>原始子网掩码</strong>：255.255.255.0 (/24)</li></ul><p>划分计划</p><ul><li><strong>借用位数</strong>：3 位</li></ul><p>结果</p><ul><li><strong>子网掩码</strong>：255.255.255.224 (/27)</li><li><strong>子网数量</strong>：(2^3 = 8)</li><li><strong>每个子网的可用主机数</strong>：(2^{(32-27)} - 2 = 2^5 - 2 = 30)</li></ul><h3 id="ip-地址与路由控制" tabindex="-1">IP 地址与路由控制 <a class="header-anchor" href="#ip-地址与路由控制" aria-label="Permalink to &quot;IP 地址与路由控制&quot;">​</a></h3><div style="display:none;" data-pagefind-meta="base64:JTdCJTIyZGF0ZSUyMiUzQTE3MTc2NDIwODA0NzMlN0Q="></div>',32);function w(k,f,C,A,y,E){return o(),s("div",null,[T,t("p",null,[e("因此，理论上IP地址的最大值为 "),t("mjx-container",p,[(o(),s("svg",c,Q)),m]),e("个，也就是最大运行约43亿台计算机连接到网络中。但是实际上，IP地址并不是根据主机个数来分配的，而是以"),g,e("。很多服务器、路由器都有多个网卡，那么它们就会有>=2的IP地址。因此让 43 亿台计算机全部连网其实是不可能的。")]),_,t("p",null,[e("以A类为例，最大主机数的计算是"),t("mjx-container",u,[(o(),s("svg",x,I)),b]),e("，减去2是因为在 IP 地址中，有两个 IP 是特殊的，分别是主机号全为 1 和 全为 0 地址。")]),V])}const B=l(i,[["render",w]]);export{v as __pageData,B as default};
